		{"int", 42, 42},
		{"float", 3.14, 3.14},
		{"time", time.Date(2023, 7, 30, 21, 5, 19, 0, time.UTC), "2023-07-30T21:05:19Z"},
		{"bytes", []byte{0x01, 0x02, 0xAB}, "0102ab"},
		{"map", map[string]any{"key": "val"}, map[string]any{"key": "val"}},
		{"slice", []any{1.0, 2.0}, []any{1.0, 2.0}},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := formatJSONValue(tt.val)
			// Compare via JSON marshaling for complex types
			gotJSON, _ := json.Marshal(got)
			wantJSON, _ := json.Marshal(tt.want)
			if string(gotJSON) != string(wantJSON) {
				t.Errorf("formatJSONValue(%v) = %s, want %s", tt.val, gotJSON, wantJSON)
			}
		})
	}
